#include <bits/stdc++.h>
using namespace std;

const int maxn = 1e5 + 10;

int n, d, ans, dep[maxn];

vector<int> e[maxn];

void dfs(int u){
	for(int i = 0; i < e[u].size(); i ++){
		int v = e[u][i];
		if(dep[v]) continue;
		dep[v] = dep[u] + 1;
		if(dep[v] <= d + 1) ans++;
		dfs(v);
	}
}

int main(){
	cin >> n >> d;
	for(int i = 1, x, y; i < n; i++){
		scanf("%d%d", &x, &y);
		e[x].push_back(y);
		e[y].push_back(x);
	}
	dep[1] = 1;
	dfs(1);
	cout << ans;
	return 0;
}
